Hi, i am working on workaround that will allow binding of void* type in Python (so Python code could hold void* as-value and use it later as function argument etc) The code below appear to be working and do the trick. However it seems that attempt to compile this code should really produce an error (by attempt to cast 'VoidPointer' to 'void *' and vice versa). So i am curious: how/why exactly this code is able to compile? And i also submitting this as an issue in case this is actually a bug.

Thanks,

```c++
#include <pybind11/pybind11.h>
#include <iostream>

struct VoidPointer
{
	void *p;
	//explicit operator void*() const { return p; }  // apper to be not needed...
};


void * foo_null_0() { return nullptr; }
void * foo_null_1() { return (void*)1; }
void * foo_null_2() { return (void*)2; }
void foo_null(void *p) { std::cout << p << std::endl; }

namespace py = pybind11;

PYBIND11_PLUGIN(example) {
    py::module m("example", "pybind11 example plugin");

	pybind11::class_<VoidPointer> cl(m, "VoidPointer");
	cl.def(pybind11::init<>());

	m.def("foo_null_0", (VoidPointer (*)()) &foo_null_0, "doc");
	m.def("foo_null_1", (VoidPointer (*)()) &foo_null_1, "doc");
	m.def("foo_null_2", (VoidPointer (*)()) &foo_null_2, "doc");

	m.def("foo_null", (void (*)(VoidPointer)) &foo_null, "doc", pybind11::arg(""));

    return m.ptr();
}
```

Hi!  I am trying to make some work with numpy arrays, but I am getting some error compilation.  Here it is the code that I am trying:

```
#include <pybind11/pybind11.h>
#include <pybind11/numpy.h>

namespace py = pybind11;

py::array_t<double> downsample_c(py::array_t<double> x) {
  auto xbuf = x.request();
  auto result = py::array_t<double>(xbuf.size);
  auto rbuf = result.request();

  double *xptr = (double *) xbuf.ptr;
  double *rptr = (double *) rbuf.ptr;

  for (size_t idx = 0; idx < xbuf.shape[0]; idx++)
    rptr[idx] = xptr[idx] + 1;

  return result;
}

PYBIND11_PLUGIN(test) {
    py::module m("downsample");
    m.def("downsample_c", &downsample_c, "Downsample array");
    return m.ptr();
}
```

and compiling this with:

```
$ c++ -O3 -shared -std=c++11 -I `python -c'import pybind11; print(pybind11.get_include())'` `python-config --cflags --ldflags` prova.c -o prova.so
```

gives me this error:

```
